mapper.select:
select * from `student_attendance`

     and id = #{id}
     and student_id = #{studentId}
     and course_id = #{courseId}
     and attendance_type = #{attendanceType}

order by attendance_time desc, id desc

mapper.update:
update `student_attendance`
student_id = #{studentId}, course_id = #{courseId}, attendance_type = #{attendanceType}, attendance_time = #{attendanceTime}, week_no = #{weekNo}, remark = #{remark},
where id = #{id}
